// ── Application logic ────────────────────────────────────────────────────
function esc(s) {
  return s.replace(/\\/g, '\\\\').replace(/'/g, "\\'");
}

function applyTranslations() {
  const activities = Object.keys(B);
  if (activities.length === 0) {
    console.log('No translation data loaded yet.');
    return;
  }

  let totalReplacements = 0;

  for (const loc of LOCALES) {
    const filePath = path.join(LOCALES_DIR, loc, 'index.ts');
    let content = fs.readFileSync(filePath, 'utf8');
    const lines = content.split('\n');
    let locReplacements = 0;

    for (const actKey of activities) {
      const data = B[actKey];
      if (!data[loc]) continue;
      const vals = data[loc];
      const [, activity] = actKey.split('.');

      // Find the activity block and replace fields within it
      let inActivity = false;
      let depth = 0;
      const actRe = new RegExp('^\\s+' + activity + ':\\s*\\{');

      for (let li = 0; li < lines.length; li++) {
        if (!inActivity && actRe.test(lines[li])) {
          inActivity = true;
          depth = 0;
        }
        if (!inActivity) continue;

        for (const ch of lines[li]) {
          if (ch === '{') depth++;
          if (ch === '}') depth--;
        }

        // Try to match each field on this line
        for (let fi = 0; fi < FIELDS.length; fi++) {
          if (!vals[fi]) continue;
          const fRe = new RegExp("^(\\s+" + FIELDS[fi] + ":\\s*)'(?:[^'\\\\]|\\\\.)*'(,?)\\s*$");
          const m = lines[li].match(fRe);
          if (m) {
            lines[li] = m[1] + "'" + esc(vals[fi]) + "'" + m[2];
            locReplacements++;
          }
        }

        if (depth <= 0) inActivity = false;
      }
    }

    if (locReplacements > 0) {
      fs.writeFileSync(filePath, lines.join('\n'), 'utf8');
      totalReplacements += locReplacements;
      console.log('  ' + LANG[loc] + ': ' + locReplacements + ' fields translated');
    }
  }

  console.log('\nTotal: ' + totalReplacements + ' translations applied');
}

applyTranslations();
